<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3">Inventory</h1><p class="text-muted mb-0">Track tools, consumables, chemicals, and reorder levels.</p></div><button class="btn btn-primary" data-bs-toggle="modal" data-bs-target="#itemModal"><i class="fa-solid fa-plus me-2"></i>Add Item</button></div>
<div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Item</th><th>Category</th><th>On hand</th><th>Reorder at</th><th>Location</th><th>Adjustment</th></tr></thead><tbody><?php foreach($items as $i): ?><tr class="<?= (float)$i['quantity']<=(float)$i['reorder_level']?'table-warning':'' ?>"><td><strong><?= e($i['name']) ?></strong><small class="d-block text-muted"><?= e($i['sku']??'') ?></small></td><td><?= e($i['category']??'') ?></td><td><?= e($i['quantity']) ?> <?= e($i['unit']) ?></td><td><?= e($i['reorder_level']) ?></td><td><?= e($i['storage_location']??'') ?></td><td><form class="d-flex gap-1" method="post" action="/portal/inventory/<?= (int)$i['id'] ?>/transaction"><?= csrf_field() ?><select name="transaction_type" class="form-select form-select-sm"><option value="receive">Receive</option><option value="use">Use</option><option value="adjust">Adjust</option></select><input name="quantity" type="number" step="0.01" class="form-control form-control-sm" style="max-width:90px" required><button class="btn btn-sm btn-outline-primary">Save</button></form></td></tr><?php endforeach ?></tbody></table></div></div>
<div class="modal fade" id="itemModal"><div class="modal-dialog"><form class="modal-content" method="post" action="/portal/inventory"><?= csrf_field() ?><div class="modal-header"><h2 class="h5 modal-title">Add Inventory Item</h2><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="row g-3"><div class="col-4"><label class="form-label">SKU</label><input name="sku" class="form-control"></div><div class="col-8"><label class="form-label">Name</label><input name="name" required class="form-control"></div><div class="col-6"><label class="form-label">Category</label><input name="category" class="form-control"></div><div class="col-3"><label class="form-label">Qty</label><input name="quantity" type="number" step=".01" value="0" class="form-control"></div><div class="col-3"><label class="form-label">Reorder</label><input name="reorder_level" type="number" step=".01" value="0" class="form-control"></div><div class="col-4"><label class="form-label">Unit</label><input name="unit" value="each" class="form-control"></div><div class="col-4"><label class="form-label">Unit cost</label><input name="unit_cost" type="number" step=".01" class="form-control"></div><div class="col-4"><label class="form-label">Location</label><input name="storage_location" class="form-control"></div></div></div><div class="modal-footer"><button class="btn btn-primary">Add Item</button></div></form></div></div>
